```typescript
import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification-element';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [notification, setNotification] = useState<NotificationProps | null>(null);

  useEffect(() => {
    if (notificationElem) {
      const notify = async (props: NotificationProps) => {
        const { heading, subheading, type } = props;
        await notificationElem.open({
          heading,
          subheading,
          type,
        });
      };
      return () => {
        notify(notification).catch(console.error);
      };
    }
  }, [notificationElem, notification]);

  return {
    notify: (props: NotificationProps) => {
      setNotification(props);
    },
  };
};

export default useNotification;
